import csv
import json
import logging
import sys
from datetime import datetime
from pathlib import Path
from typing import List, Dict, Any, Tuple

from code.src.utils.logger import get_default_logger, get_error_message

logger = get_default_logger(__name__)

def load_synthetic_summaries(path: Path) -> List[Dict[str, Any]]:
    """Load the synthetic summaries generated by T026."""
    if not path.exists():
        raise FileNotFoundError(f"Synthetic summaries file not found: {path}")
    
    summaries = []
    with open(path, 'r', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        for row in reader:
            summaries.append(row)
    
    logger.info(f"Loaded {len(summaries)} synthetic summaries from {path}")
    return summaries

def load_ground_truth(path: Path) -> Dict[str, bool]:
    """
    Load ground truth labels for synthetic data.
    The synthetic generator (T026) creates a metadata file indicating which
    records were intentionally made inconsistent.
    """
    if not path.exists():
        raise FileNotFoundError(f"Ground truth file not found: {path}")
    
    ground_truth = {}
    with open(path, 'r', encoding='utf-8') as f:
        data = json.load(f)
        # Expected structure: {"records": [{"id": "...", "is_inconsistent": true/false}, ...]}
        for record in data.get("records", []):
            record_id = record.get("id")
            if record_id:
                ground_truth[record_id] = record.get("is_inconsistent", False)
    
    logger.info(f"Loaded ground truth for {len(ground_truth)} records from {path}")
    return ground_truth

def load_audit_records(path: Path) -> List[Dict[str, Any]]:
    """Load the audit report generated by the reconstructor/validator pipeline."""
    if not path.exists():
        raise FileNotFoundError(f"Audit report file not found: {path}")
    
    records = []
    with open(path, 'r', encoding='utf-8') as f:
        data = json.load(f)
        # Expected structure: {"audit_records": [...]}
        records = data.get("audit_records", [])
    
    logger.info(f"Loaded {len(records)} audit records from {path}")
    return records

def validate_summary(summary: Dict[str, Any], audit_record: Dict[str, Any]) -> bool:
    """
    Determine if the audit record correctly identified the inconsistency status
    of the synthetic summary.
    
    Returns True if the audit record's 'is_inconsistent' flag matches the 
    ground truth derived from the synthetic generation process.
    """
    # In the synthetic data generation, we inject inconsistencies.
    # The audit record should flag these.
    # We assume the audit record contains a field 'is_inconsistent' derived from validation.
    
    # For this evaluation, we map the synthetic ID to the audit record.
    # The synthetic generator assigns IDs. The audit process should preserve or map them.
    # Assuming the audit record contains the original summary ID or a mapping exists.
    
    # Simplified logic: If the audit record has a 'data_quality_warning' or 
    # 'inconsistency_flags', it is considered flagged.
    
    is_flagged = (
        audit_record.get("is_inconsistent", False) or 
        bool(audit_record.get("inconsistency_flags")) or
        bool(audit_record.get("data_quality_warning"))
    )
    
    return is_flagged

def evaluate_detection(
    summaries: List[Dict[str, Any]],
    ground_truth: Dict[str, bool],
    audit_records: List[Dict[str, Any]]
) -> Tuple[float, float, float, Dict[str, int]]:
    """
    Compute precision, recall, and F1 score for the inconsistency detection component.
    
    Returns:
        precision, recall, f1, counts_dict
    """
    # Map audit records by ID. We assume the synthetic summary ID is preserved 
    # or can be matched. For synthetic data, the ID is usually the row index or a UUID.
    # Let's assume the audit records have an 'id' field matching the synthetic input.
    audit_map = {r.get("id"): r for r in audit_records if r.get("id")}
    
    tp = 0  # True Positives: Flagged and actually inconsistent
    fp = 0  # False Positives: Flagged but actually consistent
    fn = 0  # False Negatives: Not flagged but actually inconsistent
    tn = 0  # True Negatives: Not flagged and actually consistent
    
    # Iterate over ground truth
    for record_id, is_actually_inconsistent in ground_truth.items():
        audit_record = audit_map.get(record_id)
        
        if not audit_record:
            # If we can't find the record, treat as missing detection (FN if inconsistent)
            if is_actually_inconsistent:
                fn += 1
            continue
        
        is_detected_inconsistent = validate_summary({}, audit_record)
        
        if is_actually_inconsistent and is_detected_inconsistent:
            tp += 1
        elif not is_actually_inconsistent and is_detected_inconsistent:
            fp += 1
        elif is_actually_inconsistent and not is_detected_inconsistent:
            fn += 1
        else:
            tn += 1
    
    precision = tp / (tp + fp) if (tp + fp) > 0 else 0.0
    recall = tp / (tp + fn) if (tp + fn) > 0 else 0.0
    f1 = 2 * (precision * recall) / (precision + recall) if (precision + recall) > 0 else 0.0
    
    counts = {"tp": tp, "fp": fp, "fn": fn, "tn": tn}
    
    logger.info(f"Evaluation Results: Precision={precision:.4f}, Recall={recall:.4f}, F1={f1:.4f}")
    return precision, recall, f1, counts

def write_evaluation_results(
    results: Dict[str, Any],
    output_path: Path
) -> None:
    """Write evaluation results to a JSON file."""
    output_path.parent.mkdir(parents=True, exist_ok=True)
    with open(output_path, 'w', encoding='utf-8') as f:
        json.dump(results, f, indent=2)
    logger.info(f"Evaluation results written to {output_path}")

def main() -> int:
    """
    Main entry point for T029: Evaluate inconsistency-detection component.
    
    Loads synthetic data, runs the audit pipeline (assumed already run or run here),
    computes metrics, and asserts thresholds.
    """
    # Paths
    project_root = Path(__file__).resolve().parent.parent.parent.parent
    synthetic_data_path = project_root / "data" / "synthetic" / "summaries.csv"
    ground_truth_path = project_root / "data" / "synthetic" / "ground_truth.json"
    audit_report_path = project_root / "output" / "audit_report.json"
    evaluation_output_path = project_root / "output" / "evaluation_results.json"
    
    logger.info("Starting T029: Evaluating inconsistency detection on synthetic dataset.")
    
    try:
        # 1. Load Data
        logger.info(f"Loading synthetic summaries from {synthetic_data_path}")
        summaries = load_synthetic_summaries(synthetic_data_path)
        
        logger.info(f"Loading ground truth from {ground_truth_path}")
        ground_truth = load_ground_truth(ground_truth_path)
        
        logger.info(f"Loading audit report from {audit_report_path}")
        audit_records = load_audit_records(audit_report_path)
        
        if not summaries or not ground_truth or not audit_records:
            logger.error("One or more data sources are empty. Cannot evaluate.")
            return 1
        
        # 2. Evaluate
        precision, recall, f1, counts = evaluate_detection(summaries, ground_truth, audit_records)
        
        # 3. Assert Thresholds (FR-031)
        precision_threshold = 0.90
        recall_threshold = 0.80
        
        results = {
            "timestamp": datetime.utcnow().isoformat(),
            "task_id": "T029",
            "metrics": {
                "precision": precision,
                "recall": recall,
                "f1_score": f1
            },
            "confusion_matrix": counts,
            "thresholds": {
                "precision_min": precision_threshold,
                "recall_min": recall_threshold
            },
            "status": "PASS"
        }
        
        if precision < precision_threshold:
            results["status"] = "FAIL"
            msg = f"Precision {precision:.4f} < threshold {precision_threshold}"
            logger.error(msg)
            # Raise ERR-800 as per task description
            raise RuntimeError(f"ERR-800: {msg}")
        
        if recall < recall_threshold:
            results["status"] = "FAIL"
            msg = f"Recall {recall:.4f} < threshold {recall_threshold}"
            logger.error(msg)
            raise RuntimeError(f"ERR-800: {msg}")
        
        logger.info(f"Validation PASSED. Precision={precision:.4f} >= {precision_threshold}, Recall={recall:.4f} >= {recall_threshold}")
        
        # 4. Write Results
        write_evaluation_results(results, evaluation_output_path)
        
        return 0
        
    except FileNotFoundError as e:
        logger.error(f"Data file missing: {e}")
        return 1
    except RuntimeError as e:
        if "ERR-800" in str(e):
            logger.critical(str(e))
            return 1
        raise
    except Exception as e:
        logger.exception(f"Unexpected error during evaluation: {e}")
        return 1

if __name__ == "__main__":
    sys.exit(main())
